using System;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestHelper
    {
        public static SchoolContext CreateContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        public static void SeedDatabase(SchoolContext context)
        {
            var dept = new Department
            {
                DepartmentID = 1,
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            context.Departments.Add(dept);

            var instructor = new Instructor
            {
                ID = 1,
                LastName = "Smith",
                FirstMidName = "John",
                HireDate = DateTime.Parse("2000-01-01")
            };
            context.Instructors.Add(instructor);

            context.Courses.AddRange(
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 1 }
            );

            context.Students.AddRange(
                new Student { ID = 1, LastName = "Alexander", FirstMidName = "Carson", EnrollmentDate = DateTime.Parse("2010-09-01") },
                new Student { ID = 2, LastName = "Alonso", FirstMidName = "Meredith", EnrollmentDate = DateTime.Parse("2012-09-01") },
                new Student { ID = 3, LastName = "Barzdukas", FirstMidName = "Gytis", EnrollmentDate = DateTime.Parse("2012-09-01") }
            );

            context.SaveChanges();

            context.Enrollments.Add(new Enrollment
            {
                StudentID = 1,
                CourseID = 1050,
                Grade = Grade.A
            });

            context.CourseAssignments.Add(new CourseAssignment
            {
                InstructorID = 1,
                CourseID = 1050
            });

            context.SaveChanges();
        }
    }
}

