using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(_context);
            _controller = new StudentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewResult_WithPaginatedList()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_SortsByLastNameAscending_ByDefault()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model[0].LastName);
            Assert.Equal("Alonso", model[1].LastName);
            Assert.Equal("Barzdukas", model[2].LastName);
        }

        [Fact]
        public void Index_SortsByLastNameDescending_WhenNameDescSort()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Barzdukas", model[0].LastName);
        }

        [Fact]
        public void Index_SortsByDateAscending()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Alexander", model[0].LastName); // 2010
        }

        [Fact]
        public void Index_SortsByDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            // 2012 students come first (Alonso or Barzdukas)
            Assert.True(model[0].EnrollmentDate >= model[1].EnrollmentDate);
        }

        [Fact]
        public void Index_FiltersStudentsBySearchString()
        {
            var result = _controller.Index(null, null, "Alex", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alexander", model[0].LastName);
        }

        [Fact]
        public void Index_UsesCurrentFilter_WhenSearchStringNull()
        {
            var result = _controller.Index(null, "Alonso", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alonso", model[0].LastName);
        }

        [Fact]
        public void Index_ResetsPage_WhenNewSearchString()
        {
            _controller.Index(null, null, "Alex", null);
            // When searchString is not null, page resets to 1
            // ViewBag.CurrentFilter should be the search string
            var result = _controller.Index(null, null, "NewSearch", 5) as ViewResult;
            Assert.NotNull(result);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithStudent()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Details_IncludesEnrollments()
        {
            var result = _controller.Details(1) as ViewResult;

            var student = Assert.IsType<Student>(result.Model);
            Assert.NotNull(student.Enrollments);
            Assert.Single(student.Enrollments);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, student.EnrollmentDate);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenModelStateValid()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(4, _context.Students.Count());
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenEnrollmentDateIsMinValue()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenEnrollmentDateOutOfRange()
        {
            var student = new Student
            {
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = new DateTime(1600, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-09-01")
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewWithStudent()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void Edit_Post_RedirectsToIndex_WhenModelStateValid()
        {
            var student = _context.Students.Find(1);
            student.LastName = "UpdatedName";
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenEnrollmentDateInvalid()
        {
            var student = new Student
            {
                ID = 1,
                LastName = "Test",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenStudentDoesNotExist()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewWithStudent()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var student = Assert.IsType<Student>(result.Model);
            Assert.Equal("Alexander", student.LastName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Students.Count());
        }
    }
}

