using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _mockEnv;
        private readonly Mock<ILogger<CoursesController>> _mockLogger;
        private readonly string _tempDir;

        public CoursesControllerTests()
        {
            _context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(_context);
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockLogger = new Mock<ILogger<CoursesController>>();
            _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
            Directory.CreateDirectory(_tempDir);
            _mockEnv.Setup(e => e.WebRootPath).Returns(_tempDir);
            _mockEnv.Setup(e => e.ContentRootPath).Returns(_tempDir);
            _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
            if (Directory.Exists(_tempDir))
                Directory.Delete(_tempDir, true);
        }

        [Fact]
        public void Index_ReturnsViewResult_WithCourseList()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Equal(2, model.Count);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsViewResult_WithCourse()
        {
            var result = _controller.Details(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithNewCourse()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenValid()
        {
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Course",
                Credits = 3,
                DepartmentID = 1
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(3, _context.Courses.Count());
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course { CourseID = 9999, Credits = 3, DepartmentID = 1 };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Post_WithValidImage_SavesFile()
        {
            var course = new Course
            {
                CourseID = 8888,
                Title = "Image Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFile("test.jpg", "fake image content");

            var result = _controller.Create(course, mockFile.Object) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            var savedCourse = _context.Courses.Find(8888);
            Assert.NotNull(savedCourse.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
        }

        [Fact]
        public void Create_Post_WithInvalidExtension_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 7777,
                Title = "Bad File Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = CreateMockFile("test.exe", "malicious content");

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_WithOversizedFile_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 6666,
                Title = "Big File Course",
                Credits = 3,
                DepartmentID = 1
            };
            var mockFile = new Mock<IFormFile>();
            mockFile.Setup(f => f.FileName).Returns("big.jpg");
            mockFile.Setup(f => f.Length).Returns(10 * 1024 * 1024); // 10MB

            var result = _controller.Create(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenCourseDoesNotExist()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewWithCourse()
        {
            var result = _controller.Edit(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void Edit_Post_RedirectsToIndex_WhenValid()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Updated Chemistry",
                Credits = 4,
                DepartmentID = 1
            };
            // Detach tracked entity
            var tracked = _context.Courses.Find(1050);
            _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_WithInvalidExtension_ReturnsView()
        {
            var course = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 1
            };
            var tracked = _context.Courses.Find(1050);
            _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var mockFile = CreateMockFile("test.txt", "text content");

            var result = _controller.Edit(course, mockFile.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsViewWithCourse()
        {
            var result = _controller.Delete(1050) as ViewResult;

            Assert.NotNull(result);
            var course = Assert.IsType<Course>(result.Model);
            Assert.Equal("Chemistry", course.Title);
        }

        [Fact]
        public void DeleteConfirmed_RemovesCourseAndRedirects()
        {
            // Remove enrollment FK constraint first
            var enrollment = _context.Enrollments.FirstOrDefault(e => e.CourseID == 1050);
            if (enrollment != null) _context.Enrollments.Remove(enrollment);
            var ca = _context.CourseAssignments.FirstOrDefault(c => c.CourseID == 1050);
            if (ca != null) _context.CourseAssignments.Remove(ca);
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Courses.Find(1050));
        }

        private Mock<IFormFile> CreateMockFile(string fileName, string content)
        {
            var mockFile = new Mock<IFormFile>();
            var ms = new MemoryStream(Encoding.UTF8.GetBytes(content));
            mockFile.Setup(f => f.FileName).Returns(fileName);
            mockFile.Setup(f => f.Length).Returns(ms.Length);
            mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>()))
                .Callback<Stream>(stream => ms.CopyTo(stream));
            return mockFile;
        }
    }
}

