using System;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(_context);
            _controller = new DepartmentsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewWithDepartments()
        {
            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<System.Collections.Generic.List<Department>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewWithDepartment()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var dept = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", dept.Name);
        }

        [Fact]
        public void Create_Get_ReturnsView()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenValid()
        {
            var department = new Department
            {
                Name = "Science",
                Budget = 200000,
                StartDate = DateTime.Parse("2020-01-01")
            };

            var result = _controller.Create(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Departments.Count());
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 100000, StartDate = DateTime.Now };

            var result = _controller.Create(department) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ReturnsViewWithDepartment()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
            var dept = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", dept.Name);
        }

        [Fact]
        public void Edit_Post_RedirectsToIndex_WhenValid()
        {
            var department = new Department
            {
                DepartmentID = 1,
                Name = "Updated Engineering",
                Budget = 400000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            var tracked = _context.Departments.Find(1);
            _context.Entry(tracked).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var result = _controller.Edit(department) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                DepartmentID = 1,
                Name = "",
                Budget = 100000,
                StartDate = DateTime.Now
            };

            var result = _controller.Edit(department) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenDepartmentDoesNotExist()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewWithDepartment()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var dept = Assert.IsType<Department>(result.Model);
            Assert.Equal("Engineering", dept.Name);
        }

        [Fact]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            // Add a department with no FK constraints
            var newDept = new Department
            {
                DepartmentID = 99,
                Name = "Temp",
                Budget = 50000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            _context.Departments.Add(newDept);
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(99) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Departments.Find(99));
        }
    }
}

