using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class InstructorsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly InstructorsController _controller;

        public InstructorsControllerTests()
        {
            _context = TestHelper.CreateContext();
            TestHelper.SeedDatabase(_context);
            _controller = new InstructorsController(_context);
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        [Fact]
        public void Index_ReturnsViewWithInstructorIndexData()
        {
            var result = _controller.Index(null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Instructors);
            Assert.Single(model.Instructors);
        }

        [Fact]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            var result = _controller.Index(1, null) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Courses);
            Assert.Single(model.Courses);
        }

        [Fact]
        public void Index_WithCourseId_PopulatesEnrollments()
        {
            var result = _controller.Index(1, 1050) as ViewResult;

            var model = Assert.IsType<InstructorIndexData>(result.Model);
            Assert.NotNull(model.Enrollments);
        }

        [Fact]
        public void Details_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ReturnsViewWithInstructor()
        {
            var result = _controller.Details(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
        }

        [Fact]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.NotNull(instructor.CourseAssignments);
            Assert.Empty(instructor.CourseAssignments);
        }

        [Fact]
        public void Create_Post_RedirectsToIndex_WhenValid()
        {
            var instructor = new Instructor
            {
                LastName = "NewInstructor",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Instructors.Count());
        }

        [Fact]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            var instructor = new Instructor
            {
                LastName = "CourseInstructor",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01")
            };
            var selectedCourses = new[] { "1050" };

            var result = _controller.Create(instructor, selectedCourses) as RedirectToActionResult;

            Assert.NotNull(result);
            var saved = _context.Instructors.First(i => i.LastName == "CourseInstructor");
            Assert.NotNull(saved);
        }

        [Fact]
        public void Create_Post_ReturnsView_WhenModelStateInvalid()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };

            var result = _controller.Create(instructor, null) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Edit(1) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ReturnsNotFound_WhenInstructorDoesNotExist()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Delete_Get_ReturnsViewWithInstructor()
        {
            var result = _controller.Delete(1) as ViewResult;

            Assert.NotNull(result);
            var instructor = Assert.IsType<Instructor>(result.Model);
            Assert.Equal("Smith", instructor.LastName);
        }

        [Fact]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Add instructor with no FK issues
            var instructor = new Instructor
            {
                ID = 50,
                LastName = "ToDelete",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01"),
                CourseAssignments = new List<CourseAssignment>()
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var result = _controller.DeleteConfirmed(50) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Null(_context.Instructors.Find(50));
        }

        [Fact]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Set up instructor as dept administrator
            var dept = _context.Departments.Find(1);
            dept.InstructorID = 1;
            _context.SaveChanges();

            // Add office assignment so Delete doesn't fail on Include
            if (_context.OfficeAssignments.Find(1) == null)
            {
                _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 1, Location = "Room 1" });
                _context.SaveChanges();
            }

            var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

            Assert.NotNull(result);
            var updatedDept = _context.Departments.Find(1);
            Assert.Null(updatedDept.InstructorID);
        }
    }
}

