using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Data
{
    public class SchoolContextTests : IDisposable
    {
        private readonly SchoolContext _context;

        public SchoolContextTests()
        {
            _context = TestHelper.CreateContext();
        }

        public void Dispose()
        {
            _context.Dispose();
        }

        [Fact]
        public void CanAddAndRetrieveStudent()
        {
            var student = new Student
            {
                LastName = "TestLast",
                FirstMidName = "TestFirst",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };
            _context.Students.Add(student);
            _context.SaveChanges();

            var retrieved = _context.Students.First(s => s.LastName == "TestLast");
            Assert.Equal("TestFirst", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveInstructor()
        {
            var instructor = new Instructor
            {
                LastName = "InstrLast",
                FirstMidName = "InstrFirst",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var retrieved = _context.Instructors.First(i => i.LastName == "InstrLast");
            Assert.Equal("InstrFirst", retrieved.FirstMidName);
        }

        [Fact]
        public void CanAddAndRetrieveCourse()
        {
            var dept = new Department
            {
                Name = "TestDept",
                Budget = 100000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var course = new Course
            {
                CourseID = 5555,
                Title = "TestCourse",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();

            var retrieved = _context.Courses.Find(5555);
            Assert.NotNull(retrieved);
            Assert.Equal("TestCourse", retrieved.Title);
        }

        [Fact]
        public void CanAddAndRetrieveDepartment()
        {
            var dept = new Department
            {
                Name = "Physics",
                Budget = 250000,
                StartDate = DateTime.Parse("2020-01-01")
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();

            var retrieved = _context.Departments.First(d => d.Name == "Physics");
            Assert.Equal(250000, retrieved.Budget);
        }

        [Fact]
        public void CanAddEnrollment_WithStudentAndCourse()
        {
            TestHelper.SeedDatabase(_context);

            var enrollment = new Enrollment
            {
                StudentID = 2,
                CourseID = 4022,
                Grade = Grade.B
            };
            _context.Enrollments.Add(enrollment);
            _context.SaveChanges();

            var retrieved = _context.Enrollments.First(e => e.StudentID == 2 && e.CourseID == 4022);
            Assert.Equal(Grade.B, retrieved.Grade);
        }

        [Fact]
        public void CourseAssignment_HasCompositeKey()
        {
            TestHelper.SeedDatabase(_context);

            var ca = _context.CourseAssignments.First();
            Assert.Equal(1050, ca.CourseID);
            Assert.Equal(1, ca.InstructorID);
        }

        [Fact]
        public void CanAddOfficeAssignment()
        {
            var instructor = new Instructor
            {
                LastName = "Office",
                FirstMidName = "Test",
                HireDate = DateTime.Parse("2020-01-01")
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();

            var office = new OfficeAssignment
            {
                InstructorID = instructor.ID,
                Location = "Building A, Room 101"
            };
            _context.OfficeAssignments.Add(office);
            _context.SaveChanges();

            var retrieved = _context.OfficeAssignments.Find(instructor.ID);
            Assert.NotNull(retrieved);
            Assert.Equal("Building A, Room 101", retrieved.Location);
        }

        [Fact]
        public void Student_InheritsFromPerson()
        {
            var student = new Student
            {
                LastName = "Inherit",
                FirstMidName = "Test",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            };

            Assert.IsAssignableFrom<Person>(student);
            Assert.Equal("Inherit, Test", student.FullName);
        }

        [Fact]
        public void Instructor_InheritsFromPerson()
        {
            var instructor = new Instructor
            {
                LastName = "Inherit",
                FirstMidName = "Instr",
                HireDate = DateTime.Parse("2020-01-01")
            };

            Assert.IsAssignableFrom<Person>(instructor);
            Assert.Equal("Inherit, Instr", instructor.FullName);
        }

        [Fact]
        public void CanQueryStudentsAndInstructorsFromPeople()
        {
            TestHelper.SeedDatabase(_context);

            var people = _context.People.ToList();
            Assert.Contains(people, p => p is Student);
            Assert.Contains(people, p => p is Instructor);
        }
    }

    public class DbInitializerTests
    {
        [Fact]
        public void Initialize_SeedsDatabase_WhenEmpty()
        {
            var context = TestHelper.CreateContext();

            DbInitializer.Initialize(context);

            Assert.True(context.Students.Any());
            Assert.True(context.Instructors.Any());
            Assert.True(context.Departments.Any());
            Assert.True(context.Courses.Any());
            Assert.True(context.Enrollments.Any());
            Assert.True(context.CourseAssignments.Any());
            Assert.True(context.OfficeAssignments.Any());

            context.Dispose();
        }

        [Fact]
        public void Initialize_DoesNotReseed_WhenStudentsExist()
        {
            var context = TestHelper.CreateContext();
            context.Students.Add(new Student
            {
                LastName = "Existing",
                FirstMidName = "Student",
                EnrollmentDate = DateTime.Parse("2023-01-01")
            });
            context.SaveChanges();

            DbInitializer.Initialize(context);

            Assert.Single(context.Students);
            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesExpectedNumberOfStudents()
        {
            var context = TestHelper.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesExpectedNumberOfInstructors()
        {
            var context = TestHelper.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(5, context.Instructors.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesExpectedNumberOfDepartments()
        {
            var context = TestHelper.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(4, context.Departments.Count());
            context.Dispose();
        }

        [Fact]
        public void Initialize_CreatesExpectedNumberOfCourses()
        {
            var context = TestHelper.CreateContext();

            DbInitializer.Initialize(context);

            Assert.Equal(7, context.Courses.Count());
            context.Dispose();
        }
    }
}

