[Fact]
public void DeleteConfirmed_ClearsDepartmentAdministrator()
{
    // Set up instructor as dept administrator
    var dept = _context.Departments.First();
    dept.InstructorID = _instructorId;
    _context.SaveChanges();

    // Add office assignment so Delete doesn't fail on Include
    if (_context.OfficeAssignments.Find(_instructorId) == null)
    {
        _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = _instructorId, Location = "Room 1" });
        _context.SaveChanges();
    }

    var result = _controller.DeleteConfirmed(_instructorId) as RedirectToActionResult;

    Assert.NotNull(result);
    _context.Entry(dept).Reload();
    Assert.Null(dept.InstructorID);
}

