[Fact]
public void CanAddEnrollment_WithStudentAndCourse()
{
    TestHelper.SeedDatabase(_context);
    var studentId = _context.Students.First(s => s.LastName == "Alonso").ID;

    var enrollment = new Enrollment
    {
        StudentID = studentId,
        CourseID = 4022,
        Grade = Grade.B
    };
    _context.Enrollments.Add(enrollment);
    _context.SaveChanges();

    var retrieved = _context.Enrollments.First(e => e.StudentID == studentId && e.CourseID == 4022);
    Assert.Equal(Grade.B, retrieved.Grade);
}

